export type TooltipFormatter =
  | FormatterWithPrecision
  | DateTimeFormatter
  | TimeFrameFormatter
  | StringFormatter
  | undefined;

export type TooltipGuard = BaseGuard &
  (
    | {
        formatter: TooltipFormatter;
      }
    | {
        formatter: TooltipFormatter;
        v1: XYAccessorDataTypes;
      }
  );

export function isNumericalToolTip<
  T1 extends TooltipGuard,
  T2 extends T1 & ScaleTypesMap['numerical.linear']['tooltip'],
>(args: T1): args is Pick<T2, keyof T1> {
  return isNumerical(args);
}

export function isTimeTooltip<
  T1 extends TooltipGuard,
  T2 extends T1 & ScaleTypesMap['time']['tooltip'],
>(args: T1): args is Pick<T2, keyof T1> {
  return isTime(args);
}

export type TooltipContextHoveredPoints = {
  series: HoveredSeries;
  datapoint: HoveredDatapoint<HoveredSeries>;
  metadata: HoveredMetadata<HoveredSeries>;
};

type RectTooltipContext = {
  series: RectSeriesWithDatapoints;
  datapoint: RectDatapoint;
  metadata: RectMetadata;
};

type BarTooltipContext = {
  series: BarSeriesWithDatapoints;
  datapoint: BarDatapoint;
  metadata: BarMetadata;
};

export type TooltipContextClosestPoints = {
  series: ClosestSeries;
  datapoint: ClosestDatapoint<ClosestSeries>;
  metadata: ClosestMetadata<ClosestSeries>;
};

type AreaTooltipContext = {
  series: AreaSeriesWithDatapoints;
  datapoint: AreaDatapoint;
  metadata: AreaMetadata;
};

export function isCategoricalTooltip<
  T1 extends TooltipGuard,
  T2 extends T1 & ScaleTypesMap['categorical']['tooltip'],
>(args: T1): args is Pick<T2, keyof T1> {
  return isCategorical(args);
}

export function isRectSeries(
  series: XYChartVariantsInternal,
): series is XYChartRectSeriesInternal;

export function isRectSeries(
  series: XYChartSeriesWithDatapoints,
): series is RectSeriesWithDatapoints;

export function isRectSeries(
  series: XYChartVariantsInternal | XYChartSeriesWithDatapoints,
): series is XYChartRectSeriesInternal | RectSeriesWithDatapoints {
  return series.type === RECT_VARIANT;
}

