export function isRectTooltipContext(
  context: TooltipContextHoveredPoints,
): context is RectTooltipContext {
  return context.series.type === 'rect' && !!context.metadata;
}

export function isBarTooltipContext(
  context: TooltipContextHoveredPoints,
): context is BarTooltipContext {
  return context.series.type === 'bar' && !!context.metadata;
}

export function isAreaTooltipContext(
  context: TooltipContextClosestPoints,
): context is AreaTooltipContext {
  return context.series.type === 'area' && !!context.metadata;
}

export function isDotTooltipContent(
  content: XYChartExploreState['content'],
): content is DotSeriesContent {
  return content?.series?.type === DOT_VARIANT;
}

export function isLineTooltipContent(
  content: XYChartExploreState['content'],
): content is LineSeriesContent {
  return content?.series?.type === LINE_VARIANT;
}

export function isAreaTooltipContent(
  content: XYChartExploreState['content'],
): content is AreaSeriesContent {
  return content?.series?.type === AREA_VARIANT;
}

export function isRectDatapoint(
  datapoint:
    | RectDatapointInternal
    | DotDatapoint
    | LineDatapoint
    | BarDatapoint,
): datapoint is RectDatapointInternal {
  return 'value' in datapoint;
}

export const isStringOrValidNumber = (
  value: XYValueAccessorDataTypes,
): value is string | number => {
  return (
    typeof value === 'string' ||
    (typeof value === 'number' && !Number.isNaN(value))
  );
};

export function isValidName(
  value: XYAccessorDataTypes | boolean | null | undefined,
): value is XYAccessorDataTypes | boolean {
  return value !== null && value !== undefined && !Number.isNaN(value);
}

// Hovered series types (bar and rect)
export type HoveredSeries = BarSeriesWithDatapoints | RectSeriesWithDatapoints;

export type HoveredDatapoint<T extends HoveredSeries> =
  T extends BarSeriesWithDatapoints ? BarDatapoint : RectDatapointInternal;

export type HoveredMetadata<T extends HoveredSeries> =
  T extends BarSeriesWithDatapoints
    ? BaseMetadata & Partial<BarMetadata>
    : BaseMetadata & Partial<RectMetadata>;

export type HoveredSeriesToMetadata<T extends HoveredSeries> = Map<
  T,
  HoveredMetadata<T>
>;

export type ClosestSeries =
  | DotSeriesWithDatapoints
  | LineSeriesWithDatapoints
  | AreaSeriesWithDatapoints;

export type ClosestDatapoint<T extends ClosestSeries> =
  T extends DotSeriesWithDatapoints
    ? DotDatapoint
    : T extends LineSeriesWithDatapoints
    ? LineDatapoint
    : AreaDatapoint;

export type ClosestMetadata<T extends ClosestSeries> =
  T extends DotSeriesWithDatapoints
    ? BaseMetadata & Partial<DotMetadata>
    : T extends LineSeriesWithDatapoints
    ? BaseMetadata & Partial<LineMetadata>
    : BaseMetadata & Partial<AreaMetadata>;

export type ClosestSeriesToMetadata<T extends ClosestSeries> = Map<
  T,
  ClosestMetadata<T>
>;

export type TwoParameterAccessor<
  T extends DotDatapoint | LineDatapoint | AreaDatapoint,
> = {
  x: (
    scale: AnyXYChartScale,
    relAccessor?: (value: number) => number,
  ) => (datapoint: T) => number;
  y: (
    scale: AnyXYChartScale,
    relAccessor?: (value: number) => number,
  ) => (datapoint: T) => number;
};

export type XFourParameterAccessor = {
  x: (
    scale: AnyXYChartScale,
    datapointToMetadata: MapDatapoints,
    relAccessor?: (value: number) => number,
    isSeriesStacked?: boolean,
  ) => (datapoint: AreaDatapoint) => number;
  y: (
    scale: AnyXYChartScale,
    relAccessor?: (value: number) => number,
  ) => (datapoint: AreaDatapoint) => number;
};

export type YFourParameterAccessor = {
  x: (
    scale: AnyXYChartScale,
    relAccessor?: (value: number) => number,
  ) => (datapoint: AreaDatapoint) => number;
  y: (
    scale: AnyXYChartScale,
    datapointToMetadata: MapDatapoints,
    relAccessor?: (value: number) => number,
    isSeriesStacked?: boolean,
  ) => (datapoint: AreaDatapoint) => number;
};

export type LinearAccessors = {
  [BAND_HORIZONTAL]: TwoParameterAccessor<AreaDatapoint>;
  [BAND_VERTICAL]: TwoParameterAccessor<AreaDatapoint>;
  [DOT_VARIANT]: TwoParameterAccessor<DotDatapoint>;
  [LINE_VARIANT]: TwoParameterAccessor<LineDatapoint>;
  [AREA_HORIZONTAL]: XFourParameterAccessor;
  [AREA_VERTICAL]: YFourParameterAccessor;
};

export function isHorizontalAreaAccessors(
  accessors: LinearAccessors[keyof LinearAccessors],
): accessors is XFourParameterAccessor {
  // The horizontal area accessors have 4 parameters (scale, datapointToMetadata, relAccessor, isSeriesStacked) while the others have only 2.
  return accessors.x.length === 4;
}

export function isVerticalAreaAccessors(
  accessors: LinearAccessors[keyof LinearAccessors],
): accessors is YFourParameterAccessor {
  // The vertical area accessors have 4 parameters (scale, datapointToMetadata, relAccessor, isSeriesStacked) while the others have only 2.
  return accessors.y.length === 4;
}
